#!/usr/bin/env node
const{execFile}=require("child_process");let input="";process.stdin.setEncoding("utf8");process.stdin.on("data",chunk=>{input+=chunk});process.stdin.on("end",()=>{try{const data=JSON.parse(input);const message=String(data.message||"").replace(/[^\w\sㄱ-ㅎㅏ-ㅣ가-힣.,!?:;\-()[\]{}@#%&*/+=<>~ ]/g,"").slice(0,200);if(!message){process.exit(0)}execFile("osascript",["-e",`display notification "${message}" with title "Claude Code - KiiPS"`],{timeout:5e3},err=>{process.exit(0)})}catch(e){process.exit(0)}});setTimeout(()=>{process.exit(0)},6e3);